            ql.push(r-t1);qr.push(r-t2);
        }
        else if(r&lt;L){
            int k=ql.top()+t1;ql.pop();qr.push(k-t2);ql.push(r-t1);ql.push(r-t1);
            ans+=(L-r);
        }
        else{
            int k=qr.top()+t2;qr.pop();ql.push(k-t1);qr.push(r-t2);qr.push(r-t2);
            ans+=(r-R);
        }
        lst=now;
    }
    printf("%lld\n",ans);
    return 0;
}

